/// Creates a buffer and returns a raw pointer for C interop.
///
/// # Safety
/// The caller must call `ffi_buffer_free` with the returned pointer and the
/// same capacity when done.
#[no_mangle]
pub unsafe extern "C" fn ffi_buffer_create(
    data: *const u8,
    data_len: usize,
    capacity: usize,
    out_ptr: *mut *mut u8,
    out_len: *mut usize,
) -> i32 {
    if out_ptr.is_null() || out_len.is_null() {
        return -1;
    }

    if data.is_null() && data_len > 0 {
        return -2;
    }

    let effective_capacity = if capacity > data_len { capacity } else { data_len };

    let mut buffer = match FfiBuffer::new(effective_capacity) {
        Ok(b) => b,
        Err(_) => return -3,
    };

    if data_len > 0 && !data.is_null() {
        // Safety: caller guarantees data is valid for data_len bytes.
        let slice = std::slice::from_raw_parts(data, data_len);
        if buffer.write(slice).is_err() {
            return -4;
        }
    }

    // Transfer ownership to the caller.
    let (ptr, len, _layout) = buffer.into_raw_parts();
    *out_ptr = ptr;
    *out_len = len;

    0 // success
}

/// Frees a buffer previously created by `ffi_buffer_create`.
///
/// # Safety
/// - `ptr` must have been returned by `ffi_buffer_create`.
/// - `capacity` must match the capacity used during creation.
/// - Must only be called once per allocation.
#[no_mangle]
pub unsafe extern "C" fn ffi_buffer_free(ptr: *mut u8, capacity: usize) {
    if ptr.is_null() || capacity == 0 {
        return;
    }

    if let Ok(layout) = Layout::from_size_align(capacity, std::mem::align_of::<u8>()) {
        FfiBuffer::dealloc_raw(ptr, layout);
    }
}

